// // This module implements a simple thresholding function using Otsu's method. It takes an 8-bit grayscale pixel value and determines if it is below the threshold value. If it is below the threshold, output 1 (foreground), otherwise output 0 (background).
module otsu_threshold(
    input [7:0] pixel_value,
    input [7:0] threshold,
    output reg binary_output
);
    always @(*) begin
        if (pixel_value > threshold) begin
            binary_output = 1;
        end else begin
            binary_output = 0;
        end
    end
endmodule
